#!/usr/bin/perl

use strict;
use warnings;

my $filename = shift || die "Please provide a filename as command-line argument";

open my $filehandle, '<', $filename or die "Cannot open file: $filename";
my %word_count;

while (my $line = <$filehandle>) {
    chomp $line;
    local $_ = $line;
    for my $word (split /(\s+)/, lc($line)) {
        next if $word =~ /^\s+$/; # Skip empty strings
        $word_count{$word}++;
    }
}

close $filehandle;

my @sorted_words = sort { $word_count{$b} <=> $word_count{$a} } keys %word_count;
print for @sorted_words[0..2];

exit 0;

#!/usr/bin/perl

if (@ARGV != 1) {
    die "Usage: $0 filename";
}

my $filename = $ARGV[0];

open(my $fh, '<', $filename) or die "Could not open file: $filename";

while (my $line = <$fh>) {
    chomp $line;
    my @fields = split(',', $line);

    if ($fields[1] > 30) {
        print "$line\n";
    }
}

close($fh);

